{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-to-Recipient relationship to a 1:N relationship. This is a fundamental structural change to a central aggregate, affecting data models, external integrations, operational workflows, and billing. The change reflects a real business need — e.g., split shipments, gift deliveries to multiple parties, or B2B distribution from a single origin — but it redefines the identity and lifecycle of a Shipment.",
    "bounded_context": "Shipment Management / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing goods in transit from an origin to one or more destinations. Previously assumed a single destination; now may involve multiple delivery stops." },
      { "term": "Recipient", "definition": "A party who receives part or all of a Shipment's contents. Identified by name, address, phone number, and now also delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, safe-place authorization, signature requirements, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "In multi-recipient shipments, the recipient considered the default or lead contact for the shipment. Must be defined if business processes (notifications, billing, escalation) require a single point of contact." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. In the new model, status may need to be tracked per-recipient (partially delivered) versus at the shipment level." },
      { "term": "Delivery Attempt", "definition": "A courier's effort to hand off goods to a specific recipient at their address. In multi-recipient model, attempts are scoped per recipient." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format. These represent contractual interfaces that cannot be changed unilaterally." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients has no destination and is physically meaningless — it represents corrupt state. Goods must always be going somewhere.",
      "testable_assertion": "Any attempt to create a Shipment with an empty recipients list, or to remove the last Recipient from a Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to attempt physical delivery and to contact the recipient. Without them, the courier cannot fulfill the shipment.",
      "testable_assertion": "Creating or updating a Recipient with a null/empty name, address, or phone number MUST be rejected at the domain layer."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a single Shipment MUST have a unique delivery address.",
      "invariant": false,
      "invariant_justification": "While logically wasteful to ship to the same address twice within one shipment, there could be edge cases (different departments at same building). This is a policy the business may relax.",
      "testable_assertion": "By default, adding two Recipients with identical addresses to the same Shipment produces a warning or rejection. Policy-configurable."
    },
    {
      "id": "BR-4",
      "rule": "Delivery Preferences are optional per Recipient and default to the platform's standard delivery policy when not specified.",
      "invariant": false,
      "invariant_justification": "Preferences are a business policy overlay, not a structural constraint. The system must function without them.",
      "testable_assertion": "A Recipient added without explicit delivery preferences MUST inherit the platform default preferences and remain deliverable."
    },
    {
      "id": "BR-5",
      "rule": "Existing single-recipient shipments MUST remain fully queryable, deliverable, and operationally unchanged after migration.",
      "invariant": true,
      "invariant_justification": "2 million shipments in production represent active and historical business obligations. Data corruption or behavioral change in existing shipments would violate contractual commitments and break auditability.",
      "testable_assertion": "After migration, every existing shipment returns exactly one recipient with identical name, address, and phone as before. No shipment loses its recipient. No delivery workflow changes for in-flight shipments."
    },
    {
      "id": "BR-6",
      "rule": "Partner APIs MUST continue to receive shipment data in the current single-recipient format until partners explicitly migrate to a new contract version.",
      "invariant": true,
      "invariant_justification": "External APIs are contractual boundaries. Unilateral format changes break partner integrations, causing real-world delivery failures and potential SLA violations.",
      "testable_assertion": "For multi-recipient shipments sent to legacy partner APIs, the system MUST apply a deterministic mapping strategy (e.g., send Primary Recipient or fan out into N payloads). The strategy must be explicitly defined, not silently truncated."
    },
    {
      "id": "BR-7",
      "rule": "A multi-recipient Shipment MUST designate exactly one Primary Recipient if any business process requires a single point of contact (billing, escalation, return address).",
      "invariant": false,
      "invariant_justification": "This is a business policy to maintain backward compatibility with processes that assume one recipient. Could be changed if all downstream processes are updated.",
      "testable_assertion": "If a Shipment has multiple Recipients and no Primary Recipient is designated, the system MUST reject creation or auto-assign the first Recipient as Primary (policy decision required)."
    },
    {
      "id": "BR-8",
      "rule": "Shipment-level status must reflect the aggregate state of all Recipient deliveries. A Shipment is 'Delivered' only when ALL Recipients have received their delivery.",
      "invariant": true,
      "invariant_justification": "A shipment cannot be considered complete if goods have not reached all intended recipients. Prematurely marking a shipment as delivered is a data integrity violation that affects billing, SLA tracking, and customer trust.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending MUST have a status of 'Partially Delivered' or equivalent — never 'Delivered'."
    },
    {
      "id": "BR-9",
      "rule": "Each Recipient's delivery lifecycle (attempts, failures, successful delivery) MUST be tracked independently.",
      "invariant": true,
      "invariant_justification": "Recipients at different addresses will have independent delivery outcomes. Conflating them produces incorrect tracking data and makes redelivery impossible to manage.",
      "testable_assertion": "A failed delivery attempt for Recipient A MUST NOT affect the status or delivery history of Recipient B on the same Shipment."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The caller provides a list of one or more Recipients, each with name, address, phone, and optional delivery preferences",
      "then": "The Shipment is created with all Recipients associated, and each Recipient's delivery preferences default to platform standard if not provided"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The caller provides an empty recipients list or no recipients",
      "then": "The system rejects creation with a clear validation error: 'A Shipment requires at least one Recipient'"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried via the API",
      "then": "It returns a recipients list with exactly one entry matching the original recipient data, with no data loss or format corruption"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment exists",
      "when": "A delivery attempt succeeds for one Recipient but others are still pending",
      "then": "The individual Recipient's status is updated to 'Delivered' while the Shipment status reflects 'Partially Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment is transmitted to a legacy partner API",
      "when": "The partner API expects single-recipient format",
      "then": "The system applies the configured mapping strategy (fan-out into N API calls, or send Primary Recipient only) and logs the mapping decision for auditability"
    },
    {
      "id": "AC-6",
      "given": "A Shipment has multiple Recipients",
      "when": "A caller attempts to remove the last remaining Recipient",
      "then": "The system rejects the operation, preserving the invariant that a Shipment must always have at least one Recipient"
    },
    {
      "id": "AC-7",
      "given": "The data migration has been executed on production",
      "when": "A count query is run on all shipments and their recipients",
      "then": "All ~2 million existing shipments have exactly one Recipient each, and the total recipient count matches the total shipment count for pre-migration records"
    },
    {
      "id": "AC-8",
      "given": "A Recipient on a multi-recipient Shipment has delivery preferences specifying a time window",
      "when": "A courier views the delivery manifest for that Shipment",
      "then": "The courier sees per-Recipient delivery instructions, not a single set of instructions for the entire Shipment"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where two Recipients share the same physical address but different delivery preferences (e.g., one requires signature, one allows safe place)",
      "expected_behavior": "Both Recipients are treated as distinct delivery obligations. The courier must fulfill each Recipient's preferences independently, even if the stop is physically the same location."
    },
    {
      "scenario": "A Recipient is removed from a Shipment after goods have already been dispatched but before delivery",
      "expected_behavior": "The system must define whether in-flight recipient removal is permitted. If allowed, the removed Recipient's delivery must be cancelled and goods rerouted or returned. If not allowed, rejection with reason 'Cannot remove Recipient from in-flight Shipment'."
    },
    {
      "scenario": "All Recipients on a multi-recipient Shipment have failed delivery attempts and exhausted retries",
      "expected_behavior": "The Shipment status becomes 'Failed' or 'Return to Sender'. Each Recipient's failure reason is preserved independently for customer service resolution."
    },
    {
      "scenario": "A partner API receives a fan-out of N calls for a single multi-recipient Shipment, and one call fails while others succeed",
      "expected_behavior": "The system must retry the failed partner notification independently. It must not re-send already-acknowledged payloads. Partial partner sync state must be tracked and surfaceable."
    },
    {
      "scenario": "A Shipment is created with 50+ Recipients (bulk distribution scenario)",
      "expected_behavior": "The system should enforce a configurable upper bound on recipients per shipment to prevent abuse and operational infeasibility. The limit is a business policy, not an invariant."
    },
    {
      "scenario": "Migration is run but a subset of legacy shipments have NULL phone numbers or addresses due to historical data quality issues",
      "expected_behavior": "Migration must NOT fail on dirty data. These records should be flagged for data remediation but still migrated into the new structure. A report of non-compliant records must be generated."
    },
    {
      "scenario": "Billing is currently per-shipment. A multi-recipient shipment to 5 addresses costs significantly more to deliver than a single-recipient shipment.",
      "expected_behavior": "The billing model must be revisited. Either charge per-recipient-delivery or apply a multi-stop surcharge. Shipping a multi-recipient shipment at single-recipient price is a revenue leak."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Billing model must evolve — per-shipment pricing becomes incorrect when shipments fan out to multiple addresses. Revenue risk if multi-recipient shipments are priced as single-recipient. Migration itself carries cost: engineering time, testing, partner coordination, and potential downtime. Positive upside: multi-recipient capability unlocks new B2B and gift delivery revenue streams.",
    "operational": "HIGH. Courier routing and dispatch must handle multi-stop shipments. Delivery tracking becomes per-recipient rather than per-shipment. Customer service workflows change — a single shipment may have mixed delivery outcomes. Reporting and analytics that assumed 1:1 Shipment:Recipient must be updated. Data migration of 2M records requires careful planning, rollback strategy, and validation.",
    "user": "MEDIUM-HIGH. Senders gain the ability to ship to multiple recipients in one action (improved UX for B2B/gift use cases). Recipients see no change to their experience. Couriers need updated manifests showing per-recipient instructions. Customer service agents need training on new partial-delivery states.",
    "risk": "HIGH. This is a structural change to a core aggregate. Risks include: (1) Data migration failure or corruption on 2M records, (2) Breaking external partner integrations that expect single-recipient format, (3) Incorrect billing during transition, (4) Incomplete status tracking leading to lost deliveries, (5) Regression in single-recipient flows which represent 100% of current volume. Mitigation requires feature flags, backward-compatible APIs, and phased rollout.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "Gain multi-recipient capability. Existing single-recipient workflows must remain unchanged. Billing transparency required for new pricing model." },
      { "group": "Recipients", "impact": "Minimal direct impact. Delivery experience per-recipient remains the same. May see new delivery preference options." },
      { "group": "Couriers / Drivers", "impact": "Multi-stop routing changes. Need updated delivery manifests with per-recipient instructions and independent proof-of-delivery capture." },
      { "group": "External Partners (API consumers)", "impact": "CRITICAL. Their integrations will break if not handled. Require backward-compatible API versions and a migration timeline. Must be communicated proactively." },
      { "group": "Customer Service", "impact": "Must handle new 'Partially Delivered' states. Training required. Tooling must surface per-recipient tracking." },
      { "group": "Finance / Billing", "impact": "Pricing model must be updated before multi-recipient shipments go live. Cannot launch without billing alignment or revenue will leak." },
      { "group": "Data / Analytics", "impact": "All reports assuming 1 Shipment = 1 Recipient must be updated. KPIs like 'deliveries per shipment' change meaning." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes WHAT the new model should look like (1:N recipients with preferences) but leaves critical domain decisions undefined: What is the partner API mapping strategy? Is there a Primary Recipient concept? What happens to billing? Can recipients be modified on in-flight shipments? What are delivery preferences exactly? These gaps mean acceptance criteria are best-effort inferences from domain knowledge, not spec-driven certainties.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant is a hard domain constraint",
      "Backward compatibility for 2M existing shipments is non-negotiable",
      "Partner APIs must not break — this is a contractual boundary",
      "Per-recipient delivery tracking is required for correctness",
      "Shipment status must reflect aggregate recipient delivery state"
    ],
    "low_confidence_areas": [
      "Primary Recipient designation — not mentioned in spec but likely needed",
      "Partner API mapping strategy for multi-recipient shipments — undefined",
      "Billing model changes — not addressed but financially critical",
      "Delivery preferences schema — 'different delivery preferences' is vague",
      "Maximum recipients per shipment — no upper bound defined",
      "In-flight modification rules for recipients — not specified"
    ],
    "assumptions": [
      "The migration will convert the existing 1:1 relationship to a 1:N structure with existing recipients becoming single-element lists",
      "External partner API contracts cannot be changed without partner agreement and a transition period",
      "The existing shipment lifecycle (created → dispatched → in-transit → delivered) remains the foundation, extended with partial states",
      "Delivery preferences include at minimum: time windows, signature requirements, and safe-place authorization",
      "The change is additive — single-recipient shipments remain the common case and must not degrade in performance or usability"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'each Recipient can have different delivery preferences' but does not define what delivery preferences are. This is a new domain concept being introduced without a schema. Time windows? Signature requirements? Contactless delivery? Language preferences for notifications? The scope of 'preferences' dramatically affects implementation complexity and domain modeling.",
      "affected_stakeholders": ["Engineering", "Product", "Couriers", "Recipients"],
      "options": ["A) Define a minimal preference set (time window, signature, safe place) and extend later", "B) Make preferences a flexible key-value structure", "C) Require product to provide full preference schema before proceeding"],
      "recommendation": "Option C — require full schema. Preferences are a new first-class domain concept and cannot be designed correctly without knowing their scope."
    },
    {
      "type": "ambiguity",
      "description": "No guidance on how multi-recipient shipments should be represented when sent to external partner APIs that expect single-recipient format. Fan-out (send N separate payloads per shipment) vs. Primary-only (send one recipient, suppress others) are fundamentally different strategies with different business implications.",
      "affected_stakeholders": ["External Partners", "Engineering", "Operations"],
      "options": ["A) Fan-out: one API call per recipient, each carrying the shipment ID", "B) Primary Recipient only: partners see only the designated primary", "C) Block multi-recipient shipments from being sent to legacy partners until API v2 is ready"],
      "recommendation": "Option C is safest. Fan-out creates phantom shipments in partner systems; Primary-only silently drops data. Blocking forces the API versioning conversation."
    },
    {
      "type": "missing_context",
      "description": "Billing model impact is not addressed. If pricing is per-shipment, a 5-recipient shipment costs the same as a 1-recipient shipment despite requiring 5x the delivery effort. This is a revenue-critical gap that must be resolved before launch.",
      "affected_stakeholders": ["Finance", "Product", "Senders"],
      "options": ["A) Per-recipient pricing", "B) Base + per-additional-recipient surcharge", "C) Tiered pricing by recipient count"],
      "recommendation": "Escalate to Finance and Product immediately. This cannot be a post-launch decision — it must be encoded in the domain model from day one."
    }
  ],

  "rejection_reasons": []
}

